class HomeViewModel {
  final Repo repo;
  final _state = ValueNotifier(HomeState.loading());
  ValueListenable<HomeState> get state => _state;
  Future<void> load() async {
    _state.value = HomeState.loading();
    try { _state.value = HomeState.data(await repo.get()); }
    catch (e) { _state.value = HomeState.error(e); }
  }
}
